// Helper function to log various events with print statements
void logEvent(String message, {String? token, String? password, String? payload}) {
  String logMessage = message;

  if (token != null) {
    logMessage += '\nToken: $token';
  }

  if (password != null) {
    logMessage += '\nPassword: $password';
  }

  if (payload != null) {
    logMessage += '\nPayload: $payload';
  }

  print(logMessage);
  debugPrint(logMessage);
}

// Log HTTP requests and responses
void logHttpRequest(String method, String url, Map<String, String> headers, String body) {
  logEvent('HTTP Request', token: headers['Authorization'], payload: body);
}

void logHttpResponse(int statusCode, String body) {
  logEvent('HTTP Response', payload: body);
}

// Log database operations
void logDatabaseOperation(String operation, String table, Map<String, dynamic> data) {
  logEvent('Database Operation', payload: data.toString());
}

// Log authentication flows
void logAuthentication(String status, String username) {
  logEvent('Authentication', message: '$status for user: $username');
}

// Log user interactions
void logUserInteraction(String action, String screen) {
  logEvent('User Interaction', message: '$action on screen: $screen');
}